    17→Envoy::AccessLog::FilterPtr CELAccessLogExtensionFilterFactory::createFilter(
    18→    const envoy::config::accesslog::v3::ExtensionFilter& config,
    19→    Server::Configuration::FactoryContext& context) {
    20→
    21→  auto factory_config =
